class DirectedGraph:
    def __init__(self, n: int):
        self.n = n
        self.adj = [[] for _ in range(n)]

    def add_edge(self, u: int, v: int) -> None:
        self.adj[u].append(v)

    def _get_in_degrees(self) -> list[int]:
        in_degree = [0] * self.n
        for u in range(self.n):
            for v in self.adj[u]:
                in_degree[v] += 1
        return in_degree

    def has_cycle(self) -> bool:
        in_degree = self._get_in_degrees()
        queue = [i for i in range(self.n) if in_degree[i] == 0]
        count = 0
        idx = 0
        while idx < len(queue):
            u = queue[idx]
            idx += 1
            count += 1
            for v in self.adj[u]:
                in_degree[v] -= 1
                if in_degree[v] == 0:
                    queue.append(v)
        return count < self.n

    def topological_sort(self) -> list[int] | None:
        in_degree = self._get_in_degrees()
        queue = [i for i in range(self.n) if in_degree[i] == 0]
        order = []
        idx = 0
        while idx < len(queue):
            u = queue[idx]
            idx += 1
            order.append(u)
            for v in self.adj[u]:
                in_degree[v] -= 1
                if in_degree[v] == 0:
                    queue.append(v)
        return order if len(order) == self.n else None

    def all_topological_sorts(self) -> list[list[int]]:
        if self.has_cycle():
            return []
        in_degree = self._get_in_degrees()
        res = []
        path = []
        used = [False] * self.n

        def backtrack():
            if len(path) == self.n:
                res.append(path[:])
                return
            for i in range(self.n):
                if not used[i] and in_degree[i] == 0:
                    used[i] = True
                    path.append(i)
                    for v in self.adj[i]:
                        in_degree[v] -= 1
                    backtrack()
                    for v in self.adj[i]:
                        in_degree[v] += 1
                    path.pop()
                    used[i] = False

        backtrack()
        return res

    def longest_path(self) -> int:
        if self.has_cycle():
            return -1
        topo = self.topological_sort()
        dp = [0] * self.n
        for u in reversed(topo):
            for v in self.adj[u]:
                if dp[u] < dp[v] + 1:
                    dp[u] = dp[v] + 1
        return max(dp) if self.n > 0 else 0
