from dataclasses import dataclass
from typing import Any, Optional

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int  # higher = more important

class Calendar:
    def __init__(self):
        self._events: list[Event] = []

    @staticmethod
    def _overlaps(a: Event, b: Event) -> bool:
        return a.start < b.end and b.start < a.end

    @staticmethod
    def _subtract(intervals: list[Event], to_subtract: Event) -> list[Event]:
        res = []
        for iv in intervals:
            if not Calendar._overlaps(iv, to_subtract):
                res.append(iv)
            else:
                ov_start = max(iv.start, to_subtract.start)
                ov_end = min(iv.end, to_subtract.end)
                if iv.start < ov_start:
                    res.append(Event(iv.start, ov_start, iv.title, iv.priority))
                if ov_end < iv.end:
                    res.append(Event(ov_end, iv.end, iv.title, iv.priority))
        return res

    def add_event(self, event: Event) -> list[Event]:
        if event.start >= event.end:
            raise ValueError("start must be less than end")

        fragments = [event]
        affected = []

        # Separate existing events into higher/equal priority (conflicts that stay)
        # and lower priority (conflicts that get trimmed/removed)
        higher_or_equal = []
        lower = []

        for ex in self._events:
            if self._overlaps(ex, event):
                if ex.priority >= event.priority:
                    higher_or_equal.append(ex)
                else:
                    lower.append(ex)
            else:
                higher_or_equal.append(ex)

        # Trim fragments around higher/equal priority events
        for ex in higher_or_equal:
            if self._overlaps(ex, event):
                fragments = self._subtract(fragments, ex)

        # Handle lower priority events: remove them and keep non-overlapping parts
        new_events = []
        for ex in lower:
            affected.append(ex)
            remaining = self._subtract([ex], event)
            new_events.extend(remaining)

        # Add remaining higher/equal events
        new_events.extend(higher_or_equal)

        # Add fragments of the new event
        new_events.extend(fragments)

        self._events = new_events

        # Return modified/removed if any, else the added fragments
        if affected:
            return affected
        return fragments

    def get_events(self, start: float, end: float) -> list[Event]:
        return sorted(
            [e for e in self._events if self._overlaps(e, Event(start, end, "", 0))],
            key=lambda e: e.start
        )

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> list[tuple[float, float]]:
        # Get all events in range, sorted by start
        events = self.get_events(start, end)

        slots = []
        current = start

        for e in events:
            if e.start > current:
                slot_start = max(current, start)
                slot_end = min(e.start, end)
                if slot_end - slot_start >= min_duration:
                    slots.append((slot_start, slot_end))
            current = max(current, e.end)

        if current < end:
            slots.append((max(current, start), end))

        return slots

    def utilization(self, start: float, end: float) -> float:
        if start >= end:
            return 0.0
        total_duration = end - start
        occupied = 0.0
        for e in self._events:
            if self._overlaps(e, Event(start, end, "", 0)):
                ov_start = max(e.start, start)
                ov_end = min(e.end, end)
                occupied += max(0.0, ov_end - ov_start)
        return min(1.0, occupied / total_duration)
