def regex_match(pattern: str, text: str) -> bool:
    nodes = []
    pos = [0]

    def peek():
        return pattern[pos[0]] if pos[0] < len(pattern) else None

    def consume():
        ch = pattern[pos[0]]
        pos[0] += 1
        return ch

    def new_node(typ, *args):
        idx = len(nodes)
        nodes.append((typ, args))
        return idx

    def parse_atom():
        ch = peek()
        if ch == '(':
            consume()
            node_idx = parse_pattern()
            if peek() != ')':
                raise ValueError("Unmatched (")
            consume()
            return new_node('group', node_idx)
        elif ch == '[':
            return parse_char_class()
        elif ch == '.':
            consume()
            return new_node('dot')
        elif ch == '\\':
            consume()
            return new_node('lit', consume())
        elif ch and ch not in '*+?|)':
            consume()
            return new_node('lit', ch)
        else:
            raise ValueError(f"Unexpected {ch}")

    def parse_char_class():
        consume()
        negated = False
        if peek() == '^':
            negated = True
            consume()
        chars = set()
        while peek() and peek() != ']':
            if peek() == '\\':
                consume()
                chars.add(consume())
            else:
                ch = consume()
                if peek() == '-' and pos[0] + 1 < len(pattern) and pattern[pos[0] + 1] != ']':
                    consume()
                    end_ch = consume()
                    for c in range(ord(ch), ord(end_ch) + 1):
                        chars.add(chr(c))
                else:
                    chars.add(ch)
        if not peek():
            raise ValueError("Unterminated [")
        consume()
        return new_node('cc', chars, negated)

    def parse_quant(node_idx):
        ch = peek()
        if ch == '*':
            consume()
            return new_node('star', node_idx)
        elif ch == '+':
            consume()
            return new_node('plus', node_idx)
        elif ch == '?':
            consume()
            return new_node('quest', node_idx)
        return node_idx

    def parse_concat():
        idxs = []
        while peek() not in ('|', ')', None):
            atom_idx = parse_atom()
            idxs.append(parse_quant(atom_idx))
        if not idxs:
            return new_node('empty')
        if len(idxs) == 1:
            return idxs[0]
        return new_node('concat', tuple(idxs))

    def parse_pattern():
        left = parse_concat()
        while peek() == '|':
            consume()
            right = parse_concat()
            left = new_node('alt', left, right)
        return left

    root = parse_pattern()
    memo = {}

    def match(idx, t_pos):
        if (idx, t_pos) in memo:
            return memo[(idx, t_pos)]

        node = nodes[idx]
        typ = node[0]

        if typ == 'empty':
            res = True
        elif typ == 'lit':
            res = t_pos < len(text) and text[t_pos] == node[1]
        elif typ == 'dot':
            res = t_pos < len(text)
        elif typ == 'cc':
            chars, neg = node[1], node[2]
            if t_pos < len(text):
                in_class = text[t_pos] in chars
                res = (not in_class) if neg else in_class
            else:
                res = False
        elif typ == 'group':
            res = match(node[1], t_pos)
        elif typ == 'star':
            # Greedy: try max first
            curr = t_pos
            while curr < len(text) and match(node[1], curr):
                curr += 1
            while curr >= t_pos:
                if match(idx, curr):
                    res = True
                    break
                curr -= 1
            else:
                res = False
        elif typ == 'plus':
            # Must match at least once
            curr = t_pos
            if match(node[1], curr):
                curr += 1
                while curr < len(text) and match(node[1], curr):
                    curr += 1
                while curr > t_pos:
                    if match(idx, curr):
                        res = True
                        break
                    curr -= 1
                else:
                    res = False
            else:
                res = False
        elif typ == 'quest':
            # Try matching 1, then 0
            if match(node[1], t_pos):
                if match(idx, t_pos + 1):
                    res = True
                else:
                    res = match(idx, t_pos)
            else:
                res = match(idx, t_pos)
        elif typ == 'alt':
            res = match(node[1], t_pos) or match(node[2], t_pos)
        elif typ == 'concat':
            curr = t_pos
            res = True
            for sub_idx in node[1]:
                if not match(sub_idx, curr):
                    res = False
                    break
                # Find how many chars matched
                # Since match returns bool, we need to find the length consumed.
                # We can binary search or linear scan. Linear is simpler.
                for skip in range(1, len(text) - curr + 1):
                    if not match(sub_idx, curr + skip):
                        curr += skip - 1
                        break
                else:
                    curr += len(text) - curr
        else:
            res = False

        memo[(idx, t_pos)] = res
        return res

    return match(root, 0) and pos[0] == len(pattern)
