import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, num_virtual_nodes: int = 150):
        self.num_virtual_nodes = num_virtual_nodes
        self.ring = []
        self.hash_to_node = {}
        self.node_to_hashes = {}

    def _get_hash(self, key: str) -> int:
        return int(hashlib.md5(key.encode()).hexdigest(), 16)

    def add_node(self, node_id: str) -> None:
        if node_id in self.node_to_hashes:
            return
        hashes = []
        for i in range(self.num_virtual_nodes):
            vnode = f"{node_id}#v{i}"
            h = self._get_hash(vnode)
            hashes.append(h)
            self.hash_to_node[h] = node_id
        hashes.sort()
        self.node_to_hashes[node_id] = hashes
        self.ring.extend(hashes)
        self.ring.sort()

    def remove_node(self, node_id: str) -> None:
        if node_id not in self.node_to_hashes:
            raise KeyError(f"Node {node_id} not found")
        hashes = self.node_to_hashes.pop(node_id)
        for h in hashes:
            if self.hash_to_node.get(h) == node_id:
                del self.hash_to_node[h]
        self.ring = [h for h in self.ring if h in self.hash_to_node]

    def get_node(self, key: str) -> str | None:
        if not self.ring:
            return None
        h = self._get_hash(key)
        idx = bisect.bisect_left(self.ring, h)
        if idx == len(self.ring):
            idx = 0
        return self.hash_to_node[self.ring[idx]]

    def get_nodes_for_key(self, key: str, num_replicas: int = 3) -> list[str]:
        if not self.ring:
            return []
        nodes = []
        seen = set()
        h = self._get_hash(key)
        idx = bisect.bisect_left(self.ring, h)
        total_nodes = len(self.ring)
        count = 0
        while len(seen) < num_replicas and count < total_nodes:
            node = self.hash_to_node[self.ring[idx]]
            if node not in seen:
                seen.add(node)
                nodes.append(node)
            idx = (idx + 1) % total_nodes
            count += 1
        return nodes
